# setup_menu_principal.ps1
# Crea HomePage.tsx y actualiza AppRoutes.tsx
# No modifica ningun otro archivo existente

Write-Host "Instalando menu principal..." -ForegroundColor Cyan

Write-Host "  src/modules/dashboard/pages/HomePage.tsx" -ForegroundColor Yellow
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
$dir = Split-Path "src\modules\dashboard\pages\HomePage.tsx" -Parent
if ($dir) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\dashboard\pages\HomePage.tsx", $text, [System.Text.Encoding]::UTF8)

Write-Host "  src/routes/AppRoutes.tsx" -ForegroundColor Yellow
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
$dir = Split-Path "src\routes\AppRoutes.tsx" -Parent
if ($dir) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\routes\AppRoutes.tsx", $text, [System.Text.Encoding]::UTF8)

Write-Host ""
Write-Host "Menu principal listo!" -ForegroundColor Green
Write-Host "Abre: http://localhost:5173/" -ForegroundColor Cyan
